import { Component, EventEmitter, Output } from '@angular/core';
import { CinValidatorService } from 'src/app/services/cin/cin-validator.service';

@Component({
  selector: 'app-blog',
  templateUrl: './blog.component.html',
  styleUrls: ['./blog.component.css']
})
export class BlogComponent {
  @Output() validationComplete = new EventEmitter<{ status: string, confidence: number }>();

  selectedFile: File | null = null;
  previewUrl: string | ArrayBuffer | null = null;
  isLoading = false;
  errorMessage = '';
  validationResult: { status: string, confidence: number, valid: boolean, adjusted: boolean } | null = null;

  constructor(private cinValidator: CinValidatorService) {}

  onFileSelected(event: any): void {
    const file = event.target.files[0];
    if (file && this.validateImage(file)) {
      this.selectedFile = file;
      this.previewImage(file);
      this.errorMessage = '';
      this.validationResult = null;
    }
  }

  previewImage(file: File): void {
    const reader = new FileReader();
    reader.onload = () => this.previewUrl = reader.result;
    reader.readAsDataURL(file);
  }

  validateImage(file: File): boolean {
    const validTypes = ['image/jpeg', 'image/png'];
    if (!validTypes.includes(file.type)) {
      this.errorMessage = 'Seuls les formats JPEG et PNG sont acceptés';
      return false;
    }
    if (file.size > 5 * 1024 * 1024) {
      this.errorMessage = 'La taille de l\'image ne doit pas dépasser 5MB';
      return false;
    }
    return true;
  }

  verifyCin(): void {
    if (!this.selectedFile) {
      this.errorMessage = 'Veuillez sélectionner une image de CIN';
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    this.cinValidator.validateCin(this.selectedFile).subscribe({
      next: (response) => {
        if (response) {
          this.validationResult = {
            status: response.status,
            confidence: response.confidence,
            valid: response.valid,
            adjusted: response.adjusted
          };
          this.validationComplete.emit({ status: response.status, confidence: response.confidence });
        }
        this.isLoading = false;
      },
      error: (err) => {
        this.errorMessage = 'Erreur lors de la vérification: ' + (err.error?.message || err.message || 'Erreur inconnue');
        this.isLoading = false;
      }
    });
  }

  retryValidation(): void {
    this.selectedFile = null;
    this.previewUrl = null;
    this.validationResult = null;
  }
}
<main class="main">

        <!-- breadcrumb -->
        <div class="site-breadcrumb" style="background: url(assets/img/breadcrumb/01.jpg)">
            <div class="container">
                <h2 class="breadcrumb-title">Donation Form</h2>
                <ul class="breadcrumb-menu">
                    <li><a href="index.html">Home</a></li>
                    <li class="active">Donation Form</li>
                </ul>
            </div>
        </div>
        <!-- breadcrumb end -->


        <div class="verification-container">
  <div class="widget">
    <h3 class="title">Vérification de la Carte d'Identité Nationale</h3>

    <div class="form-group">
      <label for="cin-upload" class="form-label">
        <i class="fas fa-upload me-2"></i>
        Téléverser une image de votre CIN
      </label>
      <input type="file" id="cin-upload" class="form-control"
             (change)="onFileSelected($event)" accept="image/jpeg, image/png">
      <div class="form-text">Formats acceptés: JPEG, PNG (max 5MB)</div>
    </div>

    <div *ngIf="previewUrl" class="image-preview mt-3 mb-3">
      <img [src]="previewUrl" alt="Aperçu de la CIN" class="preview-image img-thumbnail">
    </div>

    <div *ngIf="validationResult" class="validation-result alert"
         [class.alert-success]="validationResult.status === 'valid'"
         [class.alert-danger]="validationResult.status === 'invalid'">
      <div class="d-flex justify-content-between align-items-center">
        <span>
          <strong>Résultat :</strong>
          {{ validationResult.status === 'valid' ? 'CIN Valide' : 'CIN Invalide' }}
          ({{ validationResult.confidence | number:'1.0-2' }}%)
        </span>
        <i class="fas"
           [class.fa-check-circle]="validationResult.status === 'valid'"
           [class.fa-times-circle]="validationResult.status === 'invalid'"></i>
      </div>
    </div>

    <div *ngIf="errorMessage" class="alert alert-danger mt-3">
      <i class="fas fa-exclamation-circle me-2"></i>
      {{ errorMessage }}
    </div>

    <div class="d-grid gap-2 mt-4">
      <button type="button" class="btn btn-primary"
              (click)="verifyCin()"
              [disabled]="!selectedFile || isLoading">
        <span *ngIf="!isLoading">
          <i class="fas fa-check-circle me-2"></i>Vérifier la CIN
        </span>
        <span *ngIf="isLoading">
          <i class="fas fa-spinner fa-spin me-2"></i>Vérification en cours...
        </span>
      </button>

      <button *ngIf="validationResult" type="button" class="btn btn-outline-secondary"
              (click)="retryValidation()">
        <i class="fas fa-redo me-2"></i>Nouvelle vérification
      </button>
    </div>
  </div>
</div>

    </main>
